#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10,blk=180;
typedef long long ll;
int n,a[N],b[N],L[N],R[N],mxn,loc[N],tag[N];
inline void add(int l,int r,int k)
{
	int st=loc[l],ed=loc[r];
	if(st==ed)
	{
		rep(l,r,i)a[i]+=k;memcpy(b+L[st],a+L[st],blk<<2);
		sort(b+L[st],b+R[st]+1);return;
	}
	rep(st+1,ed-1,i)tag[i]+=k;
	rep(l,R[st],i)a[i]+=k;rep(L[ed],r,i)a[i]+=k;
	memcpy(b+L[st],a+L[st],blk<<2);memcpy(b+L[ed],a+L[ed],blk<<2);
	sort(b+L[st],b+R[st]+1);sort(b+L[ed],b+R[ed]+1);
}
ll mid,K,ql,qr;
inline int fnd(int idx)
{
	if(b[R[idx]]+tag[idx]<=mid)return blk;
	if(b[L[idx]]+tag[idx]>mid)return 0;
	int l=L[idx],r=R[idx],res=l-1,Mid;
	while(l<=r)b[Mid=(l+r)>>1]+tag[idx]<=mid?(l=Mid+1,res=Mid):(r=Mid-1);
	return res-L[idx]+1;
}
inline bool check()
{
	int num=0,st=loc[ql],ed=loc[qr];
	if(st==ed){rep(ql,qr,i)if(a[i]+tag[st]<=mid)++num;return num>=K;}
	rep(st+1,ed-1,i)num+=fnd(i);
	rep(ql,R[st],i)if(a[i]+tag[st]<=mid)++num;
	rep(L[ed],qr,i)if(a[i]+tag[ed]<=mid)++num;
	return num>=K;
}
inline ll qry(int l,int r,int k)
{
	ll L=-2e9-10,R=2e9+10,res=0;ql=l;qr=r;K=k;
	while(L<=R)mid=(L+R)>>1,check()?(R=mid-1,res=mid):(L=mid+1);return res;
}
int main()
{
	n=read();int Q=read();
	rep(1,n,i)a[i]=b[i]=read();
	rep(1,n,i)
	{
		int qwq=((i-1)/blk)+1;loc[i]=qwq;
		L[qwq]=R[qwq-1]+1;R[qwq]=qwq*blk;
	}
	mxn=loc[n];R[mxn]=n;
	rep(1,mxn,i)sort(b+L[i],b+R[i]+1);
	while(Q--)
	{
		int opt=read(),l=read(),r=read();
		switch(opt)
		{
			case 1: printf("%lld\n",qry(l,r,read()));break;
			case 2: add(l,r,read());break;
		}
	}
}
